                    ns1:checksum [ a ns1:Checksum ;
                            ns1:algorithm "SHA256" ;
                            ns1:checksumValue "a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2" ] ] ;
